#include<bits/stdc++.h>
#define LL unsigned long long
using namespace std;
struct Mat{LL n,m,a[10][10];};
LL n,mod;Mat Ans,Base;
Mat operator * (const Mat &X , const Mat &Y){
    Mat Z;Z.n=X.n,Z.m=Y.m;
    for(int i=1;i<=Z.n;i++)for(int j=1;j<=Z.m;j++)Z.a[i][j]=0;
    for(int i=1;i<=Z.n;i++)for(int j=1;j<=Z.m;j++)
        for(int o=1;o<=X.m;o++)Z.a[i][j]=(Z.a[i][j]+X.a[i][o]*Y.a[o][j])%mod;
    return Z;
}
Mat QP(Mat A,Mat X,LL Y){while(Y){if(Y&1)A=X*A;X=X*X,Y>>=1;}return A;}
int main(){
    cin>>n>>mod;Ans.n=3,Ans.m=1,Base.n=3,Base.m=3;
    Ans.a[2][1]=1,Ans.a[3][1]=1;
    Base.a[1][2]=1,Base.a[2][2]=1,Base.a[2][3]=1,Base.a[3][3]=1;
    for(LL k=10;;k*=10){
        Base.a[1][1]=k%mod;
        if(n<k){Ans=QP(Ans,Base,n-k/10+1);break;}
        Ans=QP(Ans,Base,k-k/10);
    }
    cout<<Ans.a[1][1]<<"\n";
    return 0;
}
